//! # SIMD Audio Processing Optimizations\n//!\n//! This module provides high-performance SIMD-optimized audio processing functions\n//! for format conversion, mixing, effects, and real-time audio operations.\n\nuse super::{AudioFormat, Result, AudioDeviceError};\n\n#[cfg(target_arch = \"x86_64\")]\nuse std::arch::x86_64::*;\n\n#[cfg(target_arch = \"x86\")]\nuse std::arch::x86::*;\n\n#[cfg(target_arch = \"aarch64\")]\nuse std::arch::aarch64::*;\n\nuse std::simd::{f32x4, f32x8, i16x8, i32x4, i32x8, u8x16};\n\n/// SIMD capabilities detection\n#[derive(Debug, Clone, Copy)]\npub struct SimdCapabilities {\n    /// SSE support (x86/x64)\n    pub sse: bool,\n    /// SSE2 support (x86/x64)\n    pub sse2: bool,\n    /// SSE3 support (x86/x64)\n    pub sse3: bool,\n    /// SSE4.1 support (x86/x64)\n    pub sse41: bool,\n    /// AVX support (x86/x64)\n    pub avx: bool,\n    /// AVX2 support (x86/x64)\n    pub avx2: bool,\n    /// FMA support (x86/x64)\n    pub fma: bool,\n    /// NEON support (ARM)\n    pub neon: bool,\n    /// SVE support (ARM)\n    pub sve: bool,\n}\n\n/// Audio processing SIMD context\npub struct SimdAudioProcessor {\n    capabilities: SimdCapabilities,\n    /// Alignment requirement for SIMD operations\n    alignment: usize,\n}\n\nimpl SimdAudioProcessor {\n    /// Create a new SIMD audio processor with capability detection\n    pub fn new() -> Self {\n        let capabilities = Self::detect_simd_capabilities();\n        let alignment = Self::get_optimal_alignment(&capabilities);\n        \n        tracing::info!(\"SIMD capabilities detected: {:?}\", capabilities);\n        tracing::info!(\"Using alignment: {} bytes\", alignment);\n        \n        Self {\n            capabilities,\n            alignment,\n        }\n    }\n    \n    /// Detect available SIMD capabilities\n    fn detect_simd_capabilities() -> SimdCapabilities {\n        #[cfg(target_arch = \"x86_64\")]\n        {\n            SimdCapabilities {\n                sse: is_x86_feature_detected!(\"sse\"),\n                sse2: is_x86_feature_detected!(\"sse2\"),\n                sse3: is_x86_feature_detected!(\"sse3\"),\n                sse41: is_x86_feature_detected!(\"sse4.1\"),\n                avx: is_x86_feature_detected!(\"avx\"),\n                avx2: is_x86_feature_detected!(\"avx2\"),\n                fma: is_x86_feature_detected!(\"fma\"),\n                neon: false,\n                sve: false,\n            }\n        }\n        \n        #[cfg(target_arch = \"aarch64\")]\n        {\n            SimdCapabilities {\n                sse: false,\n                sse2: false,\n                sse3: false,\n                sse41: false,\n                avx: false,\n                avx2: false,\n                fma: false,\n                neon: true, // Most ARM64 processors support NEON\n                sve: false, // SVE detection would require more complex logic\n            }\n        }\n        \n        #[cfg(not(any(target_arch = \"x86_64\", target_arch = \"aarch64\")))]\n        {\n            SimdCapabilities {\n                sse: false,\n                sse2: false,\n                sse3: false,\n                sse41: false,\n                avx: false,\n                avx2: false,\n                fma: false,\n                neon: false,\n                sve: false,\n            }\n        }\n    }\n    \n    /// Get optimal alignment for SIMD operations\n    fn get_optimal_alignment(capabilities: &SimdCapabilities) -> usize {\n        if capabilities.avx2 {\n            32 // AVX2 requires 32-byte alignment\n        } else if capabilities.avx || capabilities.sse2 {\n            16 // AVX/SSE requires 16-byte alignment\n        } else {\n            8  // Conservative alignment\n        }\n    }\n    \n    /// Convert 16-bit PCM samples to f32 with SIMD acceleration\n    pub fn convert_i16_to_f32_simd(&self, input: &[i16], output: &mut [f32]) -> Result<()> {\n        if input.len() != output.len() {\n            return Err(AudioDeviceError::BufferError(\"Input and output lengths must match\".to_string()));\n        }\n        \n        #[cfg(target_arch = \"x86_64\")]\n        if self.capabilities.avx2 {\n            return self.convert_i16_to_f32_avx2(input, output);\n        }\n        \n        #[cfg(target_arch = \"x86_64\")]\n        if self.capabilities.sse2 {\n            return self.convert_i16_to_f32_sse2(input, output);\n        }\n        \n        #[cfg(target_arch = \"aarch64\")]\n        if self.capabilities.neon {\n            return self.convert_i16_to_f32_neon(input, output);\n        }\n        \n        // Fallback to portable SIMD\n        self.convert_i16_to_f32_portable_simd(input, output)\n    }\n    \n    /// Convert f32 samples to 16-bit PCM with SIMD acceleration\n    pub fn convert_f32_to_i16_simd(&self, input: &[f32], output: &mut [i16]) -> Result<()> {\n        if input.len() != output.len() {\n            return Err(AudioDeviceError::BufferError(\"Input and output lengths must match\".to_string()));\n        }\n        \n        #[cfg(target_arch = \"x86_64\")]\n        if self.capabilities.avx2 {\n            return self.convert_f32_to_i16_avx2(input, output);\n        }\n        \n        #[cfg(target_arch = \"x86_64\")]\n        if self.capabilities.sse2 {\n            return self.convert_f32_to_i16_sse2(input, output);\n        }\n        \n        #[cfg(target_arch = \"aarch64\")]\n        if self.capabilities.neon {\n            return self.convert_f32_to_i16_neon(input, output);\n        }\n        \n        // Fallback to portable SIMD\n        self.convert_f32_to_i16_portable_simd(input, output)\n    }\n    \n    /// Mix multiple audio channels with SIMD acceleration\n    pub fn mix_channels_simd(&self, inputs: &[&[f32]], output: &mut [f32], gains: &[f32]) -> Result<()> {\n        if inputs.is_empty() || gains.len() != inputs.len() {\n            return Err(AudioDeviceError::BufferError(\"Invalid input configuration\".to_string()));\n        }\n        \n        // Verify all inputs have same length\n        let sample_count = output.len();\n        for input in inputs {\n            if input.len() != sample_count {\n                return Err(AudioDeviceError::BufferError(\"All inputs must have same length\".to_string()));\n            }\n        }\n        \n        #[cfg(target_arch = \"x86_64\")]\n        if self.capabilities.avx2 {\n            return self.mix_channels_avx2(inputs, output, gains);\n        }\n        \n        #[cfg(target_arch = \"x86_64\")]\n        if self.capabilities.sse2 {\n            return self.mix_channels_sse2(inputs, output, gains);\n        }\n        \n        #[cfg(target_arch = \"aarch64\")]\n        if self.capabilities.neon {\n            return self.mix_channels_neon(inputs, output, gains);\n        }\n        \n        // Fallback to portable SIMD\n        self.mix_channels_portable_simd(inputs, output, gains)\n    }\n    \n    /// Apply gain to audio samples with SIMD acceleration\n    pub fn apply_gain_simd(&self, samples: &mut [f32], gain: f32) -> Result<()> {\n        #[cfg(target_arch = \"x86_64\")]\n        if self.capabilities.avx2 {\n            return self.apply_gain_avx2(samples, gain);\n        }\n        \n        #[cfg(target_arch = \"x86_64\")]\n        if self.capabilities.sse2 {\n            return self.apply_gain_sse2(samples, gain);\n        }\n        \n        #[cfg(target_arch = \"aarch64\")]\n        if self.capabilities.neon {\n            return self.apply_gain_neon(samples, gain);\n        }\n        \n        // Fallback to portable SIMD\n        self.apply_gain_portable_simd(samples, gain)\n    }\n    \n    /// Interleave multiple mono channels into stereo/multi-channel with SIMD\n    pub fn interleave_channels_simd(&self, inputs: &[&[f32]], output: &mut [f32]) -> Result<()> {\n        let channel_count = inputs.len();\n        let samples_per_channel = if channel_count > 0 { inputs[0].len() } else { 0 };\n        \n        if output.len() != channel_count * samples_per_channel {\n            return Err(AudioDeviceError::BufferError(\"Output size mismatch\".to_string()));\n        }\n        \n        // Verify all input channels have the same length\n        for input in inputs {\n            if input.len() != samples_per_channel {\n                return Err(AudioDeviceError::BufferError(\"All input channels must have same length\".to_string()));\n            }\n        }\n        \n        #[cfg(target_arch = \"x86_64\")]\n        if self.capabilities.avx2 && channel_count <= 8 {\n            return self.interleave_channels_avx2(inputs, output);\n        }\n        \n        #[cfg(target_arch = \"x86_64\")]\n        if self.capabilities.sse2 && channel_count <= 4 {\n            return self.interleave_channels_sse2(inputs, output);\n        }\n        \n        // Fallback to portable implementation\n        self.interleave_channels_portable(inputs, output)\n    }\n    \n    /// Deinterleave multi-channel audio into separate mono channels with SIMD\n    pub fn deinterleave_channels_simd(&self, input: &[f32], outputs: &mut [&mut [f32]]) -> Result<()> {\n        let channel_count = outputs.len();\n        let samples_per_channel = if channel_count > 0 { outputs[0].len() } else { 0 };\n        \n        if input.len() != channel_count * samples_per_channel {\n            return Err(AudioDeviceError::BufferError(\"Input size mismatch\".to_string()));\n        }\n        \n        // Verify all output channels have the same length\n        for output in outputs.iter() {\n            if output.len() != samples_per_channel {\n                return Err(AudioDeviceError::BufferError(\"All output channels must have same length\".to_string()));\n            }\n        }\n        \n        #[cfg(target_arch = \"x86_64\")]\n        if self.capabilities.avx2 && channel_count <= 8 {\n            return self.deinterleave_channels_avx2(input, outputs);\n        }\n        \n        #[cfg(target_arch = \"x86_64\")]\n        if self.capabilities.sse2 && channel_count <= 4 {\n            return self.deinterleave_channels_sse2(input, outputs);\n        }\n        \n        // Fallback to portable implementation\n        self.deinterleave_channels_portable(input, outputs)\n    }\n    \n    /// Apply a simple low-pass filter with SIMD acceleration\n    pub fn apply_lowpass_filter_simd(&self, samples: &mut [f32], cutoff_factor: f32) -> Result<()> {\n        if cutoff_factor <= 0.0 || cutoff_factor >= 1.0 {\n            return Err(AudioDeviceError::BufferError(\"Cutoff factor must be between 0 and 1\".to_string()));\n        }\n        \n        if samples.is_empty() {\n            return Ok(());\n        }\n        \n        // Simple single-pole low-pass filter: y[n] = alpha * x[n] + (1 - alpha) * y[n-1]\n        let alpha = cutoff_factor;\n        let one_minus_alpha = 1.0 - alpha;\n        \n        #[cfg(target_arch = \"x86_64\")]\n        if self.capabilities.sse2 {\n            return self.apply_lowpass_filter_sse2(samples, alpha, one_minus_alpha);\n        }\n        \n        // Fallback to scalar implementation\n        let mut previous = samples[0];\n        for sample in samples.iter_mut().skip(1) {\n            *sample = alpha * *sample + one_minus_alpha * previous;\n            previous = *sample;\n        }\n        \n        Ok(())\n    }\n    \n    // =============================================================================\n    // x86_64 AVX2 Implementations\n    // =============================================================================\n    \n    #[cfg(target_arch = \"x86_64\")]\n    #[target_feature(enable = \"avx2\")]\n    unsafe fn convert_i16_to_f32_avx2(&self, input: &[i16], output: &mut [f32]) -> Result<()> {\n        const CHUNK_SIZE: usize = 8; // Process 8 samples at once with AVX2\n        let scale = _mm256_set1_ps(1.0 / i16::MAX as f32);\n        \n        let chunks = input.len() / CHUNK_SIZE;\n        \n        for i in 0..chunks {\n            let offset = i * CHUNK_SIZE;\n            \n            // Load 8 i16 values (128 bits)\n            let input_ptr = input.as_ptr().add(offset) as *const __m128i;\n            let i16_vals = _mm_loadu_si128(input_ptr);\n            \n            // Convert i16 to i32\n            let i32_low = _mm256_cvtepi16_epi32(i16_vals);\n            \n            // Convert i32 to f32\n            let f32_vals = _mm256_cvtepi32_ps(i32_low);\n            \n            // Scale to [-1.0, 1.0] range\n            let scaled = _mm256_mul_ps(f32_vals, scale);\n            \n            // Store f32 values\n            let output_ptr = output.as_mut_ptr().add(offset);\n            _mm256_storeu_ps(output_ptr, scaled);\n        }\n        \n        // Handle remaining samples\n        let remainder = input.len() % CHUNK_SIZE;\n        if remainder > 0 {\n            let start = chunks * CHUNK_SIZE;\n            for i in 0..remainder {\n                output[start + i] = input[start + i] as f32 / i16::MAX as f32;\n            }\n        }\n        \n        Ok(())\n    }\n    \n    #[cfg(target_arch = \"x86_64\")]\n    #[target_feature(enable = \"avx2\")]\n    unsafe fn convert_f32_to_i16_avx2(&self, input: &[f32], output: &mut [i16]) -> Result<()> {\n        const CHUNK_SIZE: usize = 8;\n        let scale = _mm256_set1_ps(i16::MAX as f32);\n        \n        let chunks = input.len() / CHUNK_SIZE;\n        \n        for i in 0..chunks {\n            let offset = i * CHUNK_SIZE;\n            \n            // Load f32 values\n            let input_ptr = input.as_ptr().add(offset);\n            let f32_vals = _mm256_loadu_ps(input_ptr);\n            \n            // Clamp to [-1.0, 1.0]\n            let min_val = _mm256_set1_ps(-1.0);\n            let max_val = _mm256_set1_ps(1.0);\n            let clamped = _mm256_min_ps(_mm256_max_ps(f32_vals, min_val), max_val);\n            \n            // Scale to i16 range\n            let scaled = _mm256_mul_ps(clamped, scale);\n            \n            // Convert to i32\n            let i32_vals = _mm256_cvtps_epi32(scaled);\n            \n            // Pack i32 to i16\n            let i16_vals = _mm256_packs_epi32(i32_vals, _mm256_setzero_si256());\n            \n            // Extract and store (AVX2 packs to both lanes, we need to extract correctly)\n            let low_lane = _mm256_extracti128_si256(i16_vals, 0);\n            \n            let output_ptr = output.as_mut_ptr().add(offset) as *mut __m128i;\n            _mm_storeu_si128(output_ptr, low_lane);\n        }\n        \n        // Handle remaining samples\n        let remainder = input.len() % CHUNK_SIZE;\n        if remainder > 0 {\n            let start = chunks * CHUNK_SIZE;\n            for i in 0..remainder {\n                let clamped = input[start + i].clamp(-1.0, 1.0);\n                output[start + i] = (clamped * i16::MAX as f32) as i16;\n            }\n        }\n        \n        Ok(())\n    }\n    \n    #[cfg(target_arch = \"x86_64\")]\n    #[target_feature(enable = \"avx2\")]\n    unsafe fn mix_channels_avx2(&self, inputs: &[&[f32]], output: &mut [f32], gains: &[f32]) -> Result<()> {\n        const CHUNK_SIZE: usize = 8;\n        let sample_count = output.len();\n        let chunks = sample_count / CHUNK_SIZE;\n        \n        // Clear output first\n        for chunk in output.chunks_exact_mut(CHUNK_SIZE) {\n            let zero = _mm256_setzero_ps();\n            let output_ptr = chunk.as_mut_ptr();\n            _mm256_storeu_ps(output_ptr, zero);\n        }\n        \n        // Mix each input channel\n        for (input, &gain) in inputs.iter().zip(gains.iter()) {\n            let gain_vec = _mm256_set1_ps(gain);\n            \n            for chunk_idx in 0..chunks {\n                let offset = chunk_idx * CHUNK_SIZE;\n                \n                // Load input samples\n                let input_ptr = input.as_ptr().add(offset);\n                let input_samples = _mm256_loadu_ps(input_ptr);\n                \n                // Load current output\n                let output_ptr = output.as_mut_ptr().add(offset);\n                let current_output = _mm256_loadu_ps(output_ptr);\n                \n                // Apply gain and accumulate\n                let gained_input = _mm256_mul_ps(input_samples, gain_vec);\n                let mixed = _mm256_add_ps(current_output, gained_input);\n                \n                // Store result\n                _mm256_storeu_ps(output_ptr, mixed);\n            }\n            \n            // Handle remaining samples\n            let remainder = sample_count % CHUNK_SIZE;\n            if remainder > 0 {\n                let start = chunks * CHUNK_SIZE;\n                for i in 0..remainder {\n                    output[start + i] += input[start + i] * gain;\n                }\n            }\n        }\n        \n        Ok(())\n    }\n    \n    #[cfg(target_arch = \"x86_64\")]\n    #[target_feature(enable = \"avx2\")]\n    unsafe fn apply_gain_avx2(&self, samples: &mut [f32], gain: f32) -> Result<()> {\n        const CHUNK_SIZE: usize = 8;\n        let gain_vec = _mm256_set1_ps(gain);\n        let chunks = samples.len() / CHUNK_SIZE;\n        \n        for i in 0..chunks {\n            let offset = i * CHUNK_SIZE;\n            let samples_ptr = samples.as_mut_ptr().add(offset);\n            \n            // Load samples\n            let vals = _mm256_loadu_ps(samples_ptr);\n            \n            // Apply gain\n            let gained = _mm256_mul_ps(vals, gain_vec);\n            \n            // Store result\n            _mm256_storeu_ps(samples_ptr, gained);\n        }\n        \n        // Handle remaining samples\n        let remainder = samples.len() % CHUNK_SIZE;\n        if remainder > 0 {\n            let start = chunks * CHUNK_SIZE;\n            for i in 0..remainder {\n                samples[start + i] *= gain;\n            }\n        }\n        \n        Ok(())\n    }\n    \n    #[cfg(target_arch = \"x86_64\")]\n    #[target_feature(enable = \"avx2\")]\n    unsafe fn interleave_channels_avx2(&self, inputs: &[&[f32]], output: &mut [f32]) -> Result<()> {\n        let channel_count = inputs.len();\n        let samples_per_channel = inputs[0].len();\n        \n        // For now, handle stereo (2 channels) efficiently\n        if channel_count == 2 {\n            const CHUNK_SIZE: usize = 4; // Process 4 samples from each channel\n            let chunks = samples_per_channel / CHUNK_SIZE;\n            \n            for chunk_idx in 0..chunks {\n                let offset = chunk_idx * CHUNK_SIZE;\n                \n                // Load 4 samples from each channel\n                let left_ptr = inputs[0].as_ptr().add(offset);\n                let right_ptr = inputs[1].as_ptr().add(offset);\n                \n                let left_samples = _mm_loadu_ps(left_ptr);\n                let right_samples = _mm_loadu_ps(right_ptr);\n                \n                // Interleave using shuffle operations\n                let interleaved_low = _mm_unpacklo_ps(left_samples, right_samples);\n                let interleaved_high = _mm_unpackhi_ps(left_samples, right_samples);\n                \n                // Store interleaved samples\n                let output_offset = chunk_idx * CHUNK_SIZE * 2;\n                let output_ptr_low = output.as_mut_ptr().add(output_offset);\n                let output_ptr_high = output.as_mut_ptr().add(output_offset + 4);\n                \n                _mm_storeu_ps(output_ptr_low, interleaved_low);\n                _mm_storeu_ps(output_ptr_high, interleaved_high);\n            }\n            \n            // Handle remaining samples\n            let remainder = samples_per_channel % CHUNK_SIZE;\n            if remainder > 0 {\n                let start = chunks * CHUNK_SIZE;\n                for i in 0..remainder {\n                    let output_idx = (start + i) * 2;\n                    output[output_idx] = inputs[0][start + i];\n                    output[output_idx + 1] = inputs[1][start + i];\n                }\n            }\n            \n            return Ok(());\n        }\n        \n        // Fallback for other channel counts\n        self.interleave_channels_portable(inputs, output)\n    }\n    \n    #[cfg(target_arch = \"x86_64\")]\n    #[target_feature(enable = \"avx2\")]\n    unsafe fn deinterleave_channels_avx2(&self, input: &[f32], outputs: &mut [&mut [f32]]) -> Result<()> {\n        let channel_count = outputs.len();\n        let samples_per_channel = outputs[0].len();\n        \n        // Handle stereo efficiently\n        if channel_count == 2 {\n            const CHUNK_SIZE: usize = 4; // Process 4 stereo frames (8 samples)\n            let chunks = samples_per_channel / CHUNK_SIZE;\n            \n            for chunk_idx in 0..chunks {\n                let input_offset = chunk_idx * CHUNK_SIZE * 2;\n                let output_offset = chunk_idx * CHUNK_SIZE;\n                \n                // Load 8 interleaved samples (4 stereo frames)\n                let input_ptr = input.as_ptr().add(input_offset);\n                let samples_low = _mm_loadu_ps(input_ptr);\n                let samples_high = _mm_loadu_ps(input_ptr.add(4));\n                \n                // Deinterleave using shuffle operations\n                let left = _mm_shuffle_ps(samples_low, samples_high, 0b10001000); // Extract indices 0,2,0,2\n                let right = _mm_shuffle_ps(samples_low, samples_high, 0b11011101); // Extract indices 1,3,1,3\n                \n                // Store deinterleaved samples\n                let left_ptr = outputs[0].as_mut_ptr().add(output_offset);\n                let right_ptr = outputs[1].as_mut_ptr().add(output_offset);\n                \n                _mm_storeu_ps(left_ptr, left);\n                _mm_storeu_ps(right_ptr, right);\n            }\n            \n            // Handle remaining samples\n            let remainder = samples_per_channel % CHUNK_SIZE;\n            if remainder > 0 {\n                let start = chunks * CHUNK_SIZE;\n                for i in 0..remainder {\n                    let input_idx = (start + i) * 2;\n                    outputs[0][start + i] = input[input_idx];\n                    outputs[1][start + i] = input[input_idx + 1];\n                }\n            }\n            \n            return Ok(());\n        }\n        \n        // Fallback for other channel counts\n        self.deinterleave_channels_portable(input, outputs)\n    }\n    \n    // =============================================================================\n    // x86_64 SSE2 Implementations\n    // =============================================================================\n    \n    #[cfg(target_arch = \"x86_64\")]\n    #[target_feature(enable = \"sse2\")]\n    unsafe fn convert_i16_to_f32_sse2(&self, input: &[i16], output: &mut [f32]) -> Result<()> {\n        const CHUNK_SIZE: usize = 4;\n        let scale = _mm_set1_ps(1.0 / i16::MAX as f32);\n        let chunks = input.len() / CHUNK_SIZE;\n        \n        for i in 0..chunks {\n            let offset = i * CHUNK_SIZE;\n            \n            // Load 4 i16 values (64 bits)\n            let input_slice = &input[offset..offset + CHUNK_SIZE];\n            let i16_0 = input_slice[0] as i32;\n            let i16_1 = input_slice[1] as i32;\n            let i16_2 = input_slice[2] as i32;\n            let i16_3 = input_slice[3] as i32;\n            \n            let i32_vals = _mm_set_epi32(i16_3, i16_2, i16_1, i16_0);\n            \n            // Convert i32 to f32\n            let f32_vals = _mm_cvtepi32_ps(i32_vals);\n            \n            // Scale to [-1.0, 1.0] range\n            let scaled = _mm_mul_ps(f32_vals, scale);\n            \n            // Store f32 values\n            let output_ptr = output.as_mut_ptr().add(offset);\n            _mm_storeu_ps(output_ptr, scaled);\n        }\n        \n        // Handle remaining samples\n        let remainder = input.len() % CHUNK_SIZE;\n        if remainder > 0 {\n            let start = chunks * CHUNK_SIZE;\n            for i in 0..remainder {\n                output[start + i] = input[start + i] as f32 / i16::MAX as f32;\n            }\n        }\n        \n        Ok(())\n    }\n    \n    #[cfg(target_arch = \"x86_64\")]\n    #[target_feature(enable = \"sse2\")]\n    unsafe fn convert_f32_to_i16_sse2(&self, input: &[f32], output: &mut [i16]) -> Result<()> {\n        const CHUNK_SIZE: usize = 4;\n        let scale = _mm_set1_ps(i16::MAX as f32);\n        let chunks = input.len() / CHUNK_SIZE;\n        \n        for i in 0..chunks {\n            let offset = i * CHUNK_SIZE;\n            \n            // Load f32 values\n            let input_ptr = input.as_ptr().add(offset);\n            let f32_vals = _mm_loadu_ps(input_ptr);\n            \n            // Clamp to [-1.0, 1.0]\n            let min_val = _mm_set1_ps(-1.0);\n            let max_val = _mm_set1_ps(1.0);\n            let clamped = _mm_min_ps(_mm_max_ps(f32_vals, min_val), max_val);\n            \n            // Scale to i16 range\n            let scaled = _mm_mul_ps(clamped, scale);\n            \n            // Convert to i32\n            let i32_vals = _mm_cvtps_epi32(scaled);\n            \n            // Pack to i16 (we only use the lower 4 i16 values)\n            let i16_vals = _mm_packs_epi32(i32_vals, _mm_setzero_si128());\n            \n            // Store i16 values (extract lower 64 bits)\n            let output_slice = &mut output[offset..offset + CHUNK_SIZE];\n            let stored = _mm_extract_epi64(i16_vals, 0);\n            let stored_bytes = stored.to_le_bytes();\n            \n            output_slice[0] = i16::from_le_bytes([stored_bytes[0], stored_bytes[1]]);\n            output_slice[1] = i16::from_le_bytes([stored_bytes[2], stored_bytes[3]]);\n            output_slice[2] = i16::from_le_bytes([stored_bytes[4], stored_bytes[5]]);\n            output_slice[3] = i16::from_le_bytes([stored_bytes[6], stored_bytes[7]]);\n        }\n        \n        // Handle remaining samples\n        let remainder = input.len() % CHUNK_SIZE;\n        if remainder > 0 {\n            let start = chunks * CHUNK_SIZE;\n            for i in 0..remainder {\n                let clamped = input[start + i].clamp(-1.0, 1.0);\n                output[start + i] = (clamped * i16::MAX as f32) as i16;\n            }\n        }\n        \n        Ok(())\n    }\n    \n    #[cfg(target_arch = \"x86_64\")]\n    #[target_feature(enable = \"sse2\")]\n    unsafe fn mix_channels_sse2(&self, inputs: &[&[f32]], output: &mut [f32], gains: &[f32]) -> Result<()> {\n        const CHUNK_SIZE: usize = 4;\n        let sample_count = output.len();\n        let chunks = sample_count / CHUNK_SIZE;\n        \n        // Clear output first\n        for chunk_idx in 0..chunks {\n            let offset = chunk_idx * CHUNK_SIZE;\n            let zero = _mm_setzero_ps();\n            let output_ptr = output.as_mut_ptr().add(offset);\n            _mm_storeu_ps(output_ptr, zero);\n        }\n        \n        // Mix each input channel\n        for (input, &gain) in inputs.iter().zip(gains.iter()) {\n            let gain_vec = _mm_set1_ps(gain);\n            \n            for chunk_idx in 0..chunks {\n                let offset = chunk_idx * CHUNK_SIZE;\n                \n                // Load input samples\n                let input_ptr = input.as_ptr().add(offset);\n                let input_samples = _mm_loadu_ps(input_ptr);\n                \n                // Load current output\n                let output_ptr = output.as_mut_ptr().add(offset);\n                let current_output = _mm_loadu_ps(output_ptr);\n                \n                // Apply gain and accumulate\n                let gained_input = _mm_mul_ps(input_samples, gain_vec);\n                let mixed = _mm_add_ps(current_output, gained_input);\n                \n                // Store result\n                _mm_storeu_ps(output_ptr, mixed);\n            }\n            \n            // Handle remaining samples\n            let remainder = sample_count % CHUNK_SIZE;\n            if remainder > 0 {\n                let start = chunks * CHUNK_SIZE;\n                for i in 0..remainder {\n                    output[start + i] += input[start + i] * gain;\n                }\n            }\n        }\n        \n        Ok(())\n    }\n    \n    #[cfg(target_arch = \"x86_64\")]\n    #[target_feature(enable = \"sse2\")]\n    unsafe fn apply_gain_sse2(&self, samples: &mut [f32], gain: f32) -> Result<()> {\n        const CHUNK_SIZE: usize = 4;\n        let gain_vec = _mm_set1_ps(gain);\n        let chunks = samples.len() / CHUNK_SIZE;\n        \n        for i in 0..chunks {\n            let offset = i * CHUNK_SIZE;\n            let samples_ptr = samples.as_mut_ptr().add(offset);\n            \n            // Load samples\n            let vals = _mm_loadu_ps(samples_ptr);\n            \n            // Apply gain\n            let gained = _mm_mul_ps(vals, gain_vec);\n            \n            // Store result\n            _mm_storeu_ps(samples_ptr, gained);\n        }\n        \n        // Handle remaining samples\n        let remainder = samples.len() % CHUNK_SIZE;\n        if remainder > 0 {\n            let start = chunks * CHUNK_SIZE;\n            for i in 0..remainder {\n                samples[start + i] *= gain;\n            }\n        }\n        \n        Ok(())\n    }\n    \n    #[cfg(target_arch = \"x86_64\")]\n    #[target_feature(enable = \"sse2\")]\n    unsafe fn interleave_channels_sse2(&self, inputs: &[&[f32]], output: &mut [f32]) -> Result<()> {\n        // Similar implementation to AVX2 but using SSE2 intrinsics\n        // For brevity, falling back to portable implementation\n        self.interleave_channels_portable(inputs, output)\n    }\n    \n    #[cfg(target_arch = \"x86_64\")]\n    #[target_feature(enable = \"sse2\")]\n    unsafe fn deinterleave_channels_sse2(&self, input: &[f32], outputs: &mut [&mut [f32]]) -> Result<()> {\n        // Similar implementation to AVX2 but using SSE2 intrinsics\n        // For brevity, falling back to portable implementation\n        self.deinterleave_channels_portable(input, outputs)\n    }\n    \n    #[cfg(target_arch = \"x86_64\")]\n    #[target_feature(enable = \"sse2\")]\n    unsafe fn apply_lowpass_filter_sse2(&self, samples: &mut [f32], alpha: f32, one_minus_alpha: f32) -> Result<()> {\n        if samples.is_empty() {\n            return Ok(());\n        }\n        \n        const CHUNK_SIZE: usize = 4;\n        let alpha_vec = _mm_set1_ps(alpha);\n        let one_minus_alpha_vec = _mm_set1_ps(one_minus_alpha);\n        \n        let chunks = (samples.len() - 1) / CHUNK_SIZE; // -1 because we skip first sample\n        let mut previous = _mm_set1_ps(samples[0]);\n        \n        for chunk_idx in 0..chunks {\n            let offset = 1 + chunk_idx * CHUNK_SIZE; // +1 to skip first sample\n            let samples_ptr = samples.as_mut_ptr().add(offset);\n            \n            // Load current samples\n            let current = _mm_loadu_ps(samples_ptr);\n            \n            // Apply filter: y[n] = alpha * x[n] + (1 - alpha) * y[n-1]\n            let filtered = _mm_add_ps(\n                _mm_mul_ps(alpha_vec, current),\n                _mm_mul_ps(one_minus_alpha_vec, previous)\n            );\n            \n            // Store filtered result\n            _mm_storeu_ps(samples_ptr, filtered);\n            \n            // Update previous for next iteration (take last element of filtered)\n            previous = _mm_shuffle_ps(filtered, filtered, 0b11111111); // Broadcast last element\n        }\n        \n        // Handle remaining samples\n        let remainder_start = 1 + chunks * CHUNK_SIZE;\n        if remainder_start < samples.len() {\n            // Extract the last processed sample for continuation\n            let mut prev_scalar = samples[remainder_start - 1];\n            \n            for i in remainder_start..samples.len() {\n                samples[i] = alpha * samples[i] + one_minus_alpha * prev_scalar;\n                prev_scalar = samples[i];\n            }\n        }\n        \n        Ok(())\n    }\n    \n    // =============================================================================\n    // ARM NEON Implementations\n    // =============================================================================\n    \n    #[cfg(target_arch = \"aarch64\")]\n    fn convert_i16_to_f32_neon(&self, input: &[i16], output: &mut [f32]) -> Result<()> {\n        // NEON implementation would go here\n        // For now, falling back to portable SIMD\n        self.convert_i16_to_f32_portable_simd(input, output)\n    }\n    \n    #[cfg(target_arch = \"aarch64\")]\n    fn convert_f32_to_i16_neon(&self, input: &[f32], output: &mut [i16]) -> Result<()> {\n        // NEON implementation would go here\n        // For now, falling back to portable SIMD\n        self.convert_f32_to_i16_portable_simd(input, output)\n    }\n    \n    #[cfg(target_arch = \"aarch64\")]\n    fn mix_channels_neon(&self, inputs: &[&[f32]], output: &mut [f32], gains: &[f32]) -> Result<()> {\n        // NEON implementation would go here\n        // For now, falling back to portable SIMD\n        self.mix_channels_portable_simd(inputs, output, gains)\n    }\n    \n    #[cfg(target_arch = \"aarch64\")]\n    fn apply_gain_neon(&self, samples: &mut [f32], gain: f32) -> Result<()> {\n        // NEON implementation would go here\n        // For now, falling back to portable SIMD\n        self.apply_gain_portable_simd(samples, gain)\n    }\n    \n    // =============================================================================\n    // Portable SIMD Implementations\n    // =============================================================================\n    \n    fn convert_i16_to_f32_portable_simd(&self, input: &[i16], output: &mut [f32]) -> Result<()> {\n        const CHUNK_SIZE: usize = 8;\n        let chunks = input.len() / CHUNK_SIZE;\n        \n        for i in 0..chunks {\n            let offset = i * CHUNK_SIZE;\n            \n            // Load i16 values\n            let i16_chunk = i16x8::from_slice(&input[offset..offset + CHUNK_SIZE]);\n            \n            // Convert to i32 first (no direct i16 to f32 in portable SIMD)\n            let i32_low = i16_chunk.resize::<4>(0).cast::<i32>();\n            let i32_high = i16_chunk.resize::<4>(4).cast::<i32>();\n            \n            // Convert to f32 and scale\n            let f32_low = i32_low.cast::<f32>() / f32x4::splat(i16::MAX as f32);\n            let f32_high = i32_high.cast::<f32>() / f32x4::splat(i16::MAX as f32);\n            \n            // Combine and store\n            let result = f32_low.resize::<8>(0.0) + f32_high.resize::<8>(0.0);\n            result.copy_to_slice(&mut output[offset..offset + CHUNK_SIZE]);\n        }\n        \n        // Handle remaining samples\n        let remainder = input.len() % CHUNK_SIZE;\n        if remainder > 0 {\n            let start = chunks * CHUNK_SIZE;\n            for i in 0..remainder {\n                output[start + i] = input[start + i] as f32 / i16::MAX as f32;\n            }\n        }\n        \n        Ok(())\n    }\n    \n    fn convert_f32_to_i16_portable_simd(&self, input: &[f32], output: &mut [i16]) -> Result<()> {\n        const CHUNK_SIZE: usize = 8;\n        let chunks = input.len() / CHUNK_SIZE;\n        \n        for i in 0..chunks {\n            let offset = i * CHUNK_SIZE;\n            \n            // Load f32 values\n            let f32_chunk = f32x8::from_slice(&input[offset..offset + CHUNK_SIZE]);\n            \n            // Clamp to [-1.0, 1.0]\n            let clamped = f32_chunk.simd_clamp(f32x8::splat(-1.0), f32x8::splat(1.0));\n            \n            // Scale to i16 range\n            let scaled = clamped * f32x8::splat(i16::MAX as f32);\n            \n            // Convert to i32 first, then to i16\n            let i32_vals = scaled.cast::<i32>();\n            \n            // This is a simplified conversion - in practice you'd need to handle the conversion more carefully\n            let i16_vals: i16x8 = i32_vals.cast::<i16>();\n            \n            i16_vals.copy_to_slice(&mut output[offset..offset + CHUNK_SIZE]);\n        }\n        \n        // Handle remaining samples\n        let remainder = input.len() % CHUNK_SIZE;\n        if remainder > 0 {\n            let start = chunks * CHUNK_SIZE;\n            for i in 0..remainder {\n                let clamped = input[start + i].clamp(-1.0, 1.0);\n                output[start + i] = (clamped * i16::MAX as f32) as i16;\n            }\n        }\n        \n        Ok(())\n    }\n    \n    fn mix_channels_portable_simd(&self, inputs: &[&[f32]], output: &mut [f32], gains: &[f32]) -> Result<()> {\n        const CHUNK_SIZE: usize = 8;\n        let sample_count = output.len();\n        let chunks = sample_count / CHUNK_SIZE;\n        \n        // Initialize output to zero\n        output.fill(0.0);\n        \n        // Mix each input channel\n        for (input, &gain) in inputs.iter().zip(gains.iter()) {\n            let gain_vec = f32x8::splat(gain);\n            \n            for chunk_idx in 0..chunks {\n                let offset = chunk_idx * CHUNK_SIZE;\n                \n                // Load input and output chunks\n                let input_chunk = f32x8::from_slice(&input[offset..offset + CHUNK_SIZE]);\n                let output_chunk = f32x8::from_slice(&output[offset..offset + CHUNK_SIZE]);\n                \n                // Apply gain and mix\n                let gained_input = input_chunk * gain_vec;\n                let mixed = output_chunk + gained_input;\n                \n                // Store result\n                mixed.copy_to_slice(&mut output[offset..offset + CHUNK_SIZE]);\n            }\n            \n            // Handle remaining samples\n            let remainder = sample_count % CHUNK_SIZE;\n            if remainder > 0 {\n                let start = chunks * CHUNK_SIZE;\n                for i in 0..remainder {\n                    output[start + i] += input[start + i] * gain;\n                }\n            }\n        }\n        \n        Ok(())\n    }\n    \n    fn apply_gain_portable_simd(&self, samples: &mut [f32], gain: f32) -> Result<()> {\n        const CHUNK_SIZE: usize = 8;\n        let gain_vec = f32x8::splat(gain);\n        let chunks = samples.len() / CHUNK_SIZE;\n        \n        for i in 0..chunks {\n            let offset = i * CHUNK_SIZE;\n            \n            // Load, apply gain, and store\n            let chunk = f32x8::from_slice(&samples[offset..offset + CHUNK_SIZE]);\n            let gained = chunk * gain_vec;\n            gained.copy_to_slice(&mut samples[offset..offset + CHUNK_SIZE]);\n        }\n        \n        // Handle remaining samples\n        let remainder = samples.len() % CHUNK_SIZE;\n        if remainder > 0 {\n            let start = chunks * CHUNK_SIZE;\n            for sample in &mut samples[start..] {\n                *sample *= gain;\n            }\n        }\n        \n        Ok(())\n    }\n    \n    // =============================================================================\n    // Portable Non-SIMD Implementations\n    // =============================================================================\n    \n    fn interleave_channels_portable(&self, inputs: &[&[f32]], output: &mut [f32]) -> Result<()> {\n        let channel_count = inputs.len();\n        let samples_per_channel = inputs[0].len();\n        \n        for sample_idx in 0..samples_per_channel {\n            for channel_idx in 0..channel_count {\n                let output_idx = sample_idx * channel_count + channel_idx;\n                output[output_idx] = inputs[channel_idx][sample_idx];\n            }\n        }\n        \n        Ok(())\n    }\n    \n    fn deinterleave_channels_portable(&self, input: &[f32], outputs: &mut [&mut [f32]]) -> Result<()> {\n        let channel_count = outputs.len();\n        let samples_per_channel = outputs[0].len();\n        \n        for sample_idx in 0..samples_per_channel {\n            for channel_idx in 0..channel_count {\n                let input_idx = sample_idx * channel_count + channel_idx;\n                outputs[channel_idx][sample_idx] = input[input_idx];\n            }\n        }\n        \n        Ok(())\n    }\n    \n    /// Get SIMD capabilities\n    pub fn get_capabilities(&self) -> SimdCapabilities {\n        self.capabilities\n    }\n    \n    /// Get alignment requirement\n    pub fn get_alignment(&self) -> usize {\n        self.alignment\n    }\n}\n\nimpl Default for SimdAudioProcessor {\n    fn default() -> Self {\n        Self::new()\n    }\n}\n\n/// Global SIMD processor instance\nstatic GLOBAL_SIMD_PROCESSOR: std::sync::OnceLock<SimdAudioProcessor> = std::sync::OnceLock::new();\n\n/// Get the global SIMD processor instance\npub fn get_global_simd_processor() -> &'static SimdAudioProcessor {\n    GLOBAL_SIMD_PROCESSOR.get_or_init(SimdAudioProcessor::new)\n}\n\n/// Utility functions for easy SIMD usage\npub mod utils {\n    use super::*;\n    \n    /// Convert i16 PCM to f32 with optimal SIMD\n    pub fn convert_i16_to_f32_optimized(input: &[i16], output: &mut [f32]) -> Result<()> {\n        get_global_simd_processor().convert_i16_to_f32_simd(input, output)\n    }\n    \n    /// Convert f32 to i16 PCM with optimal SIMD\n    pub fn convert_f32_to_i16_optimized(input: &[f32], output: &mut [i16]) -> Result<()> {\n        get_global_simd_processor().convert_f32_to_i16_simd(input, output)\n    }\n    \n    /// Mix multiple channels with optimal SIMD\n    pub fn mix_channels_optimized(inputs: &[&[f32]], output: &mut [f32], gains: &[f32]) -> Result<()> {\n        get_global_simd_processor().mix_channels_simd(inputs, output, gains)\n    }\n    \n    /// Apply gain with optimal SIMD\n    pub fn apply_gain_optimized(samples: &mut [f32], gain: f32) -> Result<()> {\n        get_global_simd_processor().apply_gain_simd(samples, gain)\n    }\n    \n    /// Interleave channels with optimal SIMD\n    pub fn interleave_channels_optimized(inputs: &[&[f32]], output: &mut [f32]) -> Result<()> {\n        get_global_simd_processor().interleave_channels_simd(inputs, output)\n    }\n    \n    /// Deinterleave channels with optimal SIMD\n    pub fn deinterleave_channels_optimized(input: &[f32], outputs: &mut [&mut [f32]]) -> Result<()> {\n        get_global_simd_processor().deinterleave_channels_simd(input, outputs)\n    }\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n    use std::time::Instant;\n    \n    #[test]\n    fn test_simd_capabilities() {\n        let processor = SimdAudioProcessor::new();\n        let caps = processor.get_capabilities();\n        \n        // At least one SIMD capability should be available on modern systems\n        assert!(caps.sse || caps.sse2 || caps.avx || caps.neon);\n    }\n    \n    #[test]\n    fn test_i16_to_f32_conversion() {\n        let processor = SimdAudioProcessor::new();\n        \n        let input: Vec<i16> = vec![0, i16::MAX / 2, i16::MAX, i16::MIN, i16::MIN / 2];\n        let mut output = vec![0.0f32; input.len()];\n        \n        processor.convert_i16_to_f32_simd(&input, &mut output).unwrap();\n        \n        // Check conversion accuracy\n        assert!((output[0] - 0.0).abs() < f32::EPSILON);\n        assert!((output[1] - 0.5).abs() < 0.001);\n        assert!((output[2] - 1.0).abs() < 0.001);\n        assert!((output[3] - (-1.0)).abs() < 0.001);\n    }\n    \n    #[test]\n    fn test_f32_to_i16_conversion() {\n        let processor = SimdAudioProcessor::new();\n        \n        let input: Vec<f32> = vec![0.0, 0.5, 1.0, -1.0, -0.5];\n        let mut output = vec![0i16; input.len()];\n        \n        processor.convert_f32_to_i16_simd(&input, &mut output).unwrap();\n        \n        // Check conversion accuracy\n        assert_eq!(output[0], 0);\n        assert!((output[1] as f32 / i16::MAX as f32 - 0.5).abs() < 0.01);\n        assert_eq!(output[2], i16::MAX);\n        assert_eq!(output[3], i16::MIN);\n    }\n    \n    #[test]\n    fn test_channel_mixing() {\n        let processor = SimdAudioProcessor::new();\n        \n        let input1 = vec![1.0, 0.5, 0.0, -0.5];\n        let input2 = vec![0.0, 0.5, 1.0, 0.5];\n        let inputs = vec![input1.as_slice(), input2.as_slice()];\n        let gains = vec![1.0, 0.5];\n        let mut output = vec![0.0; 4];\n        \n        processor.mix_channels_simd(&inputs, &mut output, &gains).unwrap();\n        \n        // Check mixed results\n        assert_eq!(output[0], 1.0 + 0.0 * 0.5);\n        assert_eq!(output[1], 0.5 + 0.5 * 0.5);\n        assert_eq!(output[2], 0.0 + 1.0 * 0.5);\n        assert_eq!(output[3], -0.5 + 0.5 * 0.5);\n    }\n    \n    #[test]\n    fn test_gain_application() {\n        let processor = SimdAudioProcessor::new();\n        \n        let mut samples = vec![1.0, 0.5, 0.0, -0.5, -1.0];\n        let original = samples.clone();\n        let gain = 0.5;\n        \n        processor.apply_gain_simd(&mut samples, gain).unwrap();\n        \n        // Check gain application\n        for (i, &original_sample) in original.iter().enumerate() {\n            assert!((samples[i] - original_sample * gain).abs() < f32::EPSILON);\n        }\n    }\n    \n    #[test]\n    fn test_channel_interleaving() {\n        let processor = SimdAudioProcessor::new();\n        \n        let left = vec![1.0, 2.0, 3.0, 4.0];\n        let right = vec![0.1, 0.2, 0.3, 0.4];\n        let inputs = vec![left.as_slice(), right.as_slice()];\n        let mut output = vec![0.0; 8];\n        \n        processor.interleave_channels_simd(&inputs, &mut output).unwrap();\n        \n        // Check interleaved output\n        assert_eq!(output[0], 1.0);\n        assert_eq!(output[1], 0.1);\n        assert_eq!(output[2], 2.0);\n        assert_eq!(output[3], 0.2);\n        assert_eq!(output[4], 3.0);\n        assert_eq!(output[5], 0.3);\n        assert_eq!(output[6], 4.0);\n        assert_eq!(output[7], 0.4);\n    }\n    \n    #[test]\n    fn benchmark_simd_vs_scalar() {\n        let processor = SimdAudioProcessor::new();\n        \n        const SIZE: usize = 44100 * 2; // 2 seconds of 44.1kHz audio\n        let input: Vec<i16> = (0..SIZE).map(|i| (i % 32768) as i16).collect();\n        let mut simd_output = vec![0.0f32; SIZE];\n        let mut scalar_output = vec![0.0f32; SIZE];\n        \n        // SIMD benchmark\n        let start = Instant::now();\n        processor.convert_i16_to_f32_simd(&input, &mut simd_output).unwrap();\n        let simd_duration = start.elapsed();\n        \n        // Scalar benchmark\n        let start = Instant::now();\n        for i in 0..SIZE {\n            scalar_output[i] = input[i] as f32 / i16::MAX as f32;\n        }\n        let scalar_duration = start.elapsed();\n        \n        println!(\"SIMD duration: {:?}\", simd_duration);\n        println!(\"Scalar duration: {:?}\", scalar_duration);\n        \n        // SIMD should be faster (though this may not always be true in debug builds)\n        // assert!(simd_duration < scalar_duration);\n        \n        // Results should be the same\n        for i in 0..SIZE {\n            assert!((simd_output[i] - scalar_output[i]).abs() < 0.001);\n        }\n    }\n}"